import { toast } from '../components/ui/use-toast';

/**
 * 通用的复制到剪贴板函数，包含降级方案
 * 适用于公网环境，解决HTTPS要求和权限问题
 */
export const copyToClipboard = async (text: string, successMessage?: string): Promise<boolean> => {
  try {
    // 方案1: 现代浏览器的 Clipboard API (需要HTTPS或localhost)
    if (navigator.clipboard && window.isSecureContext) {
      await navigator.clipboard.writeText(text);
      if (successMessage) {
        toast({
          title: "复制成功",
          description: successMessage,
        });
      }
      return true;
    }
    
    // 方案2: 降级到传统的 document.execCommand (兼容性更好)
    const textArea = document.createElement('textarea');
    textArea.value = text;
    textArea.style.position = 'fixed';
    textArea.style.left = '-999999px';
    textArea.style.top = '-999999px';
    document.body.appendChild(textArea);
    textArea.focus();
    textArea.select();
    
    const successful = document.execCommand('copy');
    document.body.removeChild(textArea);
    
    if (successful) {
      if (successMessage) {
        toast({
          title: "复制成功",
          description: successMessage,
        });
      }
      return true;
    }
    
    // 方案3: 如果都失败了，显示文本让用户手动复制
    throw new Error('复制失败');
    
  } catch (error) {
    console.error('复制到剪贴板失败:', error);
    
    // 降级方案: 显示模态框让用户手动复制
    showCopyModal(text);
    return false;
  }
};

/**
 * 显示复制模态框，让用户手动复制
 */
const showCopyModal = (text: string) => {
  // 创建模态框
  const modal = document.createElement('div');
  modal.style.cssText = `
    position: fixed;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    justify-content: center;
    align-items: center;
    z-index: 10000;
  `;
  
  const content = document.createElement('div');
  content.style.cssText = `
    background: white;
    padding: 20px;
    border-radius: 8px;
    max-width: 80%;
    max-height: 80%;
    overflow: auto;
    box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
  `;
  
  content.innerHTML = `
    <div style="margin-bottom: 15px;">
      <h3 style="margin: 0 0 10px 0; font-size: 16px; font-weight: 600;">手动复制链接</h3>
      <p style="margin: 0 0 10px 0; color: #666; font-size: 14px;">
        由于浏览器安全限制，请手动复制以下内容：
      </p>
    </div>
    <textarea 
      readonly 
      style="
        width: 100%;
        height: 120px;
        padding: 10px;
        border: 1px solid #ddd;
        border-radius: 4px;
        font-family: monospace;
        font-size: 12px;
        resize: vertical;
        box-sizing: border-box;
      "
    >${text}</textarea>
    <div style="margin-top: 15px; display: flex; gap: 10px; justify-content: flex-end;">
      <button 
        id="selectAllBtn"
        style="
          padding: 8px 16px;
          background: #3b82f6;
          color: white;
          border: none;
          border-radius: 4px;
          cursor: pointer;
          font-size: 14px;
        "
      >
        全选
      </button>
      <button 
        id="closeModalBtn"
        style="
          padding: 8px 16px;
          background: #6b7280;
          color: white;
          border: none;
          border-radius: 4px;
          cursor: pointer;
          font-size: 14px;
        "
      >
        关闭
      </button>
    </div>
  `;
  
  modal.appendChild(content);
  document.body.appendChild(modal);
  
  const textarea = content.querySelector('textarea') as HTMLTextAreaElement;
  const selectAllBtn = content.querySelector('#selectAllBtn') as HTMLButtonElement;
  const closeModalBtn = content.querySelector('#closeModalBtn') as HTMLButtonElement;
  
  // 自动选中文本
  textarea.focus();
  textarea.select();
  
  // 全选按钮
  selectAllBtn.addEventListener('click', () => {
    textarea.select();
  });
  
  // 关闭按钮
  const closeModal = () => {
    document.body.removeChild(modal);
  };
  
  closeModalBtn.addEventListener('click', closeModal);
  modal.addEventListener('click', (e) => {
    if (e.target === modal) {
      closeModal();
    }
  });
  
  // ESC键关闭
  const handleKeyDown = (e: KeyboardEvent) => {
    if (e.key === 'Escape') {
      closeModal();
      document.removeEventListener('keydown', handleKeyDown);
    }
  };
  document.addEventListener('keydown', handleKeyDown);
  
  // 显示提示
  toast({
    title: "请手动复制",
    description: "由于浏览器安全限制，请在弹出的窗口中手动复制链接",
    variant: "default",
  });
};

/**
 * 批量复制多个链接
 */
export const copyMultipleLinks = async (
  links: string[], 
  format: 'simple' | 'title' | 'detailed' = 'simple',
  itemInfo?: { code?: string; author?: string; size?: string; resolution?: string }
): Promise<boolean> => {
  let formattedText = '';
  
  switch (format) {
    case 'simple':
      formattedText = links.join('\n');
      break;
    case 'title':
      if (itemInfo?.code && itemInfo?.author) {
        formattedText = `${itemInfo.code} - ${itemInfo.author}\n${links.join('\n')}`;
      } else {
        formattedText = links.join('\n');
      }
      break;
    case 'detailed':
      if (itemInfo) {
        const info = `${itemInfo.code || 'N/A'} | ${itemInfo.author || 'N/A'} | ${itemInfo.size || 'N/A'} | ${itemInfo.resolution || 'N/A'}`;
        formattedText = `${info}\n${links.join('\n')}`;
      } else {
        formattedText = links.join('\n');
      }
      break;
    default:
      formattedText = links.join('\n');
  }
  
  return await copyToClipboard(formattedText, `已复制 ${links.length} 个链接到剪贴板`);
};

/**
 * 复制单个磁力链接
 */
export const copyMagnetLink = async (magnetLink: string, itemInfo?: { code?: string; author?: string }): Promise<boolean> => {
  const message = itemInfo ? `已复制 ${itemInfo.code} 的磁力链接` : '已复制磁力链接';
  return await copyToClipboard(magnetLink, message);
};

/**
 * 复制ED2K链接
 */
export const copyEd2kLink = async (ed2kLink: string, itemInfo?: { code?: string; author?: string }): Promise<boolean> => {
  const message = itemInfo ? `已复制 ${itemInfo.code} 的ED2K链接` : '已复制ED2K链接';
  return await copyToClipboard(ed2kLink, message);
};
